def max_investment_return(budget, startups):
    # Grouped knapsack DP
    # dp[j] = maximum return achievable with exactly j budget available
    dp = [0] * (budget + 1)

    for options in startups:
        # new_dp starts as a copy (representing the choice of skipping this startup)
        new_dp = dp[:]
        for cost, ret in options:
            for j in range(cost, budget + 1):
                new_dp[j] = max(new_dp[j], dp[j - cost] + ret)
        dp = new_dp

    return dp[budget]
